import{_ as t,a,b as o,c as i}from"./chunks/wizard-step6.CcFfa22f.js";import{_ as n,o as r,c as l,ag as s}from"./chunks/framework.BqfgOMAh.js";const k=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/getting-started.md","filePath":"en/guide/getting-started.md"}'),u={name:"en/guide/getting-started.md"};function p(d,e,c,h,g,m){return r(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Get up and running with NexusFlow in 5 minutes</p><p>This guide walks you through installation, configuration, and your first AI conversation.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you begin, make sure your environment meets the following requirements:</p><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Operating System</td><td>Windows 10 / 11</td></tr><tr><td>Unreal Engine</td><td>Unreal Engine 5.6 or 5.7</td></tr><tr><td>LLM API Key</td><td>Any one of: OpenAI / Anthropic / Google Gemini / DeepSeek / Zhipu GLM / MiniMax / Qwen / Kimi</td></tr></tbody></table><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li>Download the latest <code>.exe</code> installer from <a href="https://github.com/maxzhao/NexusFlow/releases" target="_blank" rel="noreferrer">GitHub Releases</a></li><li>Run the installer to complete the NexusFlow desktop app setup</li><li>Purchase and install the UE plugin from <a href="https://www.fab.com/" target="_blank" rel="noreferrer">Fab.com</a> (see <a href="./installation">Installation Guide</a> for details)</li></ol><h2 id="first-run-wizard" tabindex="-1">First-Run Wizard <a class="header-anchor" href="#first-run-wizard" aria-label="Permalink to &quot;First-Run Wizard&quot;">​</a></h2><p>When you first launch NexusFlow and click the floating ball on your screen, a setup wizard will guide you through all the necessary configuration. The wizard has 6 steps:</p><h3 id="step-1-welcome" tabindex="-1">Step 1: Welcome <a class="header-anchor" href="#step-1-welcome" aria-label="Permalink to &quot;Step 1: Welcome&quot;">​</a></h3><p><img src="'+t+'" alt="Setup Wizard - Welcome"></p><p>A brief introduction to NexusFlow. Click &quot;Start Setup&quot; to continue, or &quot;Skip&quot; to go straight to the app.</p><h3 id="step-2-configure-ai-model" tabindex="-1">Step 2: Configure AI Model <a class="header-anchor" href="#step-2-configure-ai-model" aria-label="Permalink to &quot;Step 2: Configure AI Model&quot;">​</a></h3><p><img src="'+a+'" alt="Setup Wizard - AI Model Configuration"></p><p>This is the most important step — you need to add at least one AI model to use the chat feature.</p><ol><li>Select a <strong>Provider</strong>: OpenAI, Anthropic, Google Gemini, DeepSeek, Zhipu GLM, MiniMax, Qwen, Kimi, or Custom</li><li>Enter a <strong>Model Name</strong> (a custom label for display in the model list)</li><li>Enter your <strong>API Key</strong>, or an environment variable reference such as <code>${OPENAI_API_KEY}</code></li><li>Enter the <strong>Model ID</strong> (e.g., <code>gpt-5.4</code>, <code>claude-opus-4-6</code>)</li><li>Optionally adjust Temperature and Max Tokens</li><li>Click Save</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you choose Custom Provider, you&#39;ll also need to enter an API endpoint URL and select the communication protocol (OpenAI Compatible / OpenAI Responses API / Anthropic Messages API / Google Gemini API). When using an environment variable reference, the real API key is read by the backend at runtime and only <code>${ENV_NAME}</code> is stored in app configuration.</p></div><h3 id="step-3-ue-plugin-check" tabindex="-1">Step 3: UE Plugin Check <a class="header-anchor" href="#step-3-ue-plugin-check" aria-label="Permalink to &quot;Step 3: UE Plugin Check&quot;">​</a></h3><p><img src="'+o+'" alt="Setup Wizard - Plugin Check"></p><p>The wizard automatically detects whether Unreal Engine is installed on your computer and whether the NexusFlow plugin is properly set up.</p><ul><li>✅ Plugin detected: You&#39;re good to go</li><li>❌ Plugin not found: See <a href="./installation#install-the-ue-plugin">Installation Guide</a> for manual installation</li></ul><h3 id="step-4-anonymous-analytics" tabindex="-1">Step 4: Anonymous Analytics <a class="header-anchor" href="#step-4-anonymous-analytics" aria-label="Permalink to &quot;Step 4: Anonymous Analytics&quot;">​</a></h3><p>Choose whether to allow anonymous usage data collection. This data is used solely to improve the product and contains no personal information. You can change this setting at any time.</p><h3 id="step-5-feature-tour" tabindex="-1">Step 5: Feature Tour <a class="header-anchor" href="#step-5-feature-tour" aria-label="Permalink to &quot;Step 5: Feature Tour&quot;">​</a></h3><p>A quick overview of NexusFlow&#39;s three core features:</p><ul><li><strong>Floating Ball</strong>: A desktop quick-access entry point — click to open AI chat</li><li><strong>AI Chat Sidebar</strong>: The main interface for communicating with AI, supporting floating and docked modes</li><li><strong>UE Quick Menu</strong>: 17 AI operations across right-click menus and toolbars in the UE Editor</li></ul><h3 id="step-6-complete" tabindex="-1">Step 6: Complete <a class="header-anchor" href="#step-6-complete" aria-label="Permalink to &quot;Step 6: Complete&quot;">​</a></h3><p><img src="'+i+'" alt="Setup Wizard - Complete"></p><p>You&#39;re all set! Click &quot;Get Started&quot; to enter the AI chat interface.</p><div class="info custom-block"><p class="custom-block-title">Keyboard Shortcuts</p><p>During the wizard, press <code>Enter</code> to proceed to the next step, or <code>Escape</code> to skip the wizard entirely.</p></div><h2 id="ue-plugin-setup-dialog" tabindex="-1">UE Plugin Setup Dialog <a class="header-anchor" href="#ue-plugin-setup-dialog" aria-label="Permalink to &quot;UE Plugin Setup Dialog&quot;">​</a></h2><p>The first time UE starts with the NexusFlow plugin enabled, you may see a <strong>NexusFlow Setup</strong> dialog. This is normal — the plugin checks whether the desktop app is installed and whether the embedding model is ready.</p><ul><li>If everything is in order, no dialog appears</li><li>If something is missing, click <strong>Later</strong> to dismiss it and set things up later</li><li>See <a href="./installation#ue-plugin-first-launch">Installation Guide — UE Plugin First Launch</a> for full details</li></ul><h2 id="your-first-conversation" tabindex="-1">Your First Conversation <a class="header-anchor" href="#your-first-conversation" aria-label="Permalink to &quot;Your First Conversation&quot;">​</a></h2><p>Once the wizard is complete, you&#39;re ready to start using NexusFlow:</p><ol><li><strong>Launch NexusFlow</strong> — A floating ball appears on your desktop (a blue-purple gradient circle)</li><li><strong>Launch the UE Editor</strong> — Make sure the NexusFlow plugin is enabled</li><li><strong>Wait for connection</strong> — The status bar at the bottom of the sidebar turns from red to green, showing the project name and UE version</li><li><strong>Open a Blueprint</strong> — Open the Blueprint you want to work with in UE</li><li><strong>Click the floating ball</strong> — Opens the AI chat sidebar</li><li><strong>Type a message</strong> — For example: &quot;Explain what this Blueprint does&quot;</li></ol><p>The AI will automatically read the information from your currently open Blueprint, analyze it, and respond.</p><div class="warning custom-block"><p class="custom-block-title">Important</p><p>Make sure UE is connected before starting a conversation (the bottom status bar should show a green dot). If not connected, the AI won&#39;t be able to operate on Blueprints.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./ai-chat">AI Chat</a> — Explore the chat interface in detail</li><li><a href="./blueprint-operations">Blueprint Operations</a> — Common conversation examples and tips</li><li><a href="./settings">Settings</a> — Customize NexusFlow to your preferences</li><li><a href="./installation">Installation Guide</a> — See the full installation walkthrough</li></ul>',40)])])}const y=n(u,[["render",p]]);export{k as __pageData,y as default};
